entry.content:
javascript Style Guide结尾无多余空格像你每次餐后刷牙一样，提交代码前请清空你JS文件中所有多余的空格。 使用分号科学研究表明，良好的分号使用习惯会给我们带来很大的益处。请在行末等应该使用分号的地方使用它。 一行最多80字符虽然现在的显示器越来越宽，但是我们的智慧却没有同比增长，请保持一行最多80个字符，这样会让阅读更容易些。 使用单引号除非你书写JSON，否则请全部使用单引号。 Right: 1var foo = 'bar'; Wrong: 1var foo = "bar"; 在同一行打开括号在同一行里打开括号，使用方法如下 Right: 123if (true) &#123; console.log('winning');&#125; Wrong: 1234if (true)&#123; console.log('losing');&#125; 同时，请注意在条件语句前后使用空格隔开（小括号前后）。 链式方法如果要使用链式方法，每种方法应该独占一行。 而且在这些方法前使用相同的缩进，让他们更容易被识别为同一链式方法的一部分 Right: 1234567User .findOne(&#123; name: 'foo' &#125;) .populate('bar') .exec(function(err, user) &#123; return true; &#125;);` Wrong: 1234567891011121314151617181920212223User.findOne(&#123; name: 'foo' &#125;).populate('bar').exec(function(err, user) &#123; return true;&#125;);User.findOne(&#123; name: 'foo' &#125;) .populate('bar') .exec(function(err, user) &#123; return true; &#125;);User.findOne(&#123; name: 'foo' &#125;).populate('bar').exec(function(err, user) &#123; return true;&#125;);User.findOne(&#123; name: 'foo' &#125;).populate('bar') .exec(function(err, user) &#123; return true; &#125;);` 变量为了避免全局变量污染，请在定义变量时使用var进行声明 12345// badsuperPower = new SuperPower();// goodvar superPower = new SuperPower(); 每个变量的声明之前请都使用一个var ，这样会让你很容易的辨识变量并且不用关心需要使用;还是,结尾。 123456789101112131415// badvar items = getItems(), goSportsTeam = true, dragonball = 'z';// bad// (compare to above, and try to spot the mistake)var items = getItems(), goSportsTeam = true; dragonball = 'z';// goodvar items = getItems();var goSportsTeam = true;var dragonball = 'z'; 未进行赋值的变量声明请放到最后。这样会方便你以后查找已赋值的变量，并方便你对新变量进行赋值。 123456789101112131415161718// badvar i, len, dragonball, items = getItems(), goSportsTeam = true;// badvar i;var items = getItems();var dragonball;var goSportsTeam = true;var len;// goodvar items = getItems();var goSportsTeam = true;var dragonball;var length;var i; 在作用域的顶部声明需要的变量。这有助于解决变量声明和变量赋值相关的问题。 12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758// badfunction() &#123; test(); console.log('doing stuff..'); //..other stuff.. var name = getName(); if (name === 'test') &#123; return false; &#125; return name;&#125;// goodfunction() &#123; var name = getName(); test(); console.log('doing stuff..'); //..other stuff.. if (name === 'test') &#123; return false; &#125; return name;&#125;// bad - unnecessary function callfunction() &#123; var name = getName(); if (!arguments.length) &#123; return false; &#125; this.setFirstName(name); return true;&#125;// goodfunction() &#123; var name; if (!arguments.length) &#123; return false; &#125; name = getName(); this.setFirstName(name); return true;&#125; 使用小驼峰命名法（lowerCamelCase）命名变量、属性和函数变量、属性和函数的命名应使用小驼峰命名法（lowerCamelCase）。它应该是可描述的，避免使用单变量或者特别冷僻的缩写。 Right: 1var adminUser = db.query('SELECT * FROM users ...'); Wrong: 1var admin_user = db.query('SELECT * FROM users ...'); 使用大驼峰命名法（UpperCamelCase）命名类名类名应用大驼峰命名法命名。 Right: 12function BankAccount() &#123;&#125; Wrong: 12function bank_Account() &#123;&#125; 用大写声明常量常量的声明（常规变量或静态类属性）应使用大写字母声明。 Right: 12345var SECOND = 1 * 1000;function File() &#123;&#125;File.FULL_PERMISSIONS = 0777; Wrong: 12345const SECOND = 1 * 1000;function File() &#123;&#125;File.fullPermissions = 0777; 对象/数组简短的数组声明时占据一行使用逗号隔开，key：value的形式请按照如下展示。 Right: 12345var a = ['hello', 'world'];var b = &#123; good: 'code', 'is generally': 'pretty',&#125;; Wrong: 123456var a = [ 'hello', 'world'];var b = &#123;"good": 'code' , is generally: 'pretty' &#125;; 对象使用字面语法创建。 12345// badvar item = new Object();// goodvar item = &#123;&#125;; 不要使用保留字做key值。 1234567891011// badvar superman = &#123; default: &#123; clark: 'kent' &#125;, private: true&#125;;// goodvar superman = &#123; defaults: &#123; clark: 'kent' &#125;, hidden: true&#125;; 用可读性强的同义词来替代关键字。 1234567891011121314// badvar superman = &#123; class: 'alien'&#125;;// badvar superman = &#123; klass: 'alien'&#125;;// goodvar superman = &#123; type: 'alien'&#125;; 数组使用字面语法创建 12345// badvar items = new Array();// goodvar items = []; 对数组赋值时，使用数组push方法而不是直接赋值是个好习惯 1234567var someStack = [];// badsomeStack[someStack.length] = 'abracadabra';// goodsomeStack.push('abracadabra'); 当你拷贝一个数组时，使用数组方法slice会大幅提高性能。 1234567891011var len = items.length;var itemsCopy = [];var i;// badfor (i = 0; i &lt; len; i++) &#123; itemsCopy[i] = items[i];&#125;// gooditemsCopy = items.slice(); 转换一个类对象的数组为普通数组，使用数组的slice方法。 1234function trigger() &#123; var args = Array.prototype.slice.call(arguments); ...&#125; 函数函数表达式: 1234567891011121314// anonymous function expressionvar anonymous = function() &#123; return true;&#125;;// named function expressionvar named = function named() &#123; return true;&#125;;// immediately-invoked function expression (IIFE)(function() &#123; console.log('Welcome to the Internet. Please follow me.');&#125;)(); 不要在非功能模块声明函数（if, while, etc），如果需要这做，请声明一个变量来接替它， 浏览器虽然允许你这样做，但是会形成不同的解析。 1234567891011121314// badif (currentUser) &#123; function test() &#123; console.log('Nope.'); &#125;&#125;// goodvar test;if (currentUser) &#123; test = function test() &#123; console.log('Yup.'); &#125;;&#125; 不要将 arguments 作为形参传递。 123456789// badfunction nope(name, options, arguments) &#123; // ...stuff...&#125;// goodfunction yup(name, options, args) &#123; // ...stuff...&#125; 属性在直接访问属性时使用. 来进行访问。 12345678910var luke = &#123; jedi: true, age: 28&#125;;// badvar isJedi = luke['jedi'];// goodvar isJedi = luke.jedi; 用[]来访问变量传递的属性。 12345678910var luke = &#123; jedi: true, age: 28&#125;;function getProp(prop) &#123; return luke[prop];&#125;var isJedi = getProp('jedi'); 使用 === 操作在需要的地方使用 === 会按照你所期望的进行操作。从而避免那些编程中规则上的漏洞。 Right: 1234var a = 0;if (a !== '') &#123; console.log('winning');&#125; Wrong: 1234var a = 0;if (a == '') &#123; console.log('losing');&#125; 使用多行形式的三目运算符不要使用单行形式的三目运算符，用多行形式来替代它。 Right: 123var foo = (a === b) ? 1 : 2; Wrong: 1var foo = (a === b) ? 1 : 2; 不要扩展JavaScript原生的原型不要扩展JavaScript原生的原型，将来你一定会感谢你自己的。 Right: 1234var a = [];if (!a.length) &#123; console.log('winning');&#125; Wrong: 12345678Array.prototype.empty = function() &#123; return !this.length;&#125;var a = [];if (a.empty()) &#123; console.log('losing');&#125; 使用描述性条件任何特殊的条件，都应被声明成一个变量或一个函数来整体使用。 Right: 12345var isValidPassword = password.length &gt;= 4 &amp;&amp; /^(?=.*\d).&#123;4,&#125;$/.test(password);if (isValidPassword) &#123; console.log('winning');&#125; Wrong: 123if (password.length &gt;= 4 &amp;&amp; /^(?=.*\d).&#123;4,&#125;$/.test(password)) &#123; console.log('losing');&#125; 编写小型函数保持你的函数尽量短小，一个函数只实现一个功能。尽量保持一个函数不要超过15行代码，让你的函数更加容易被阅读理解。 Return为了避免函数的if语句深度嵌套，请在需要return时尽可能早的使用它。 Right: 1234567891011function isPercentage(val) &#123; if (val &lt; 0) &#123; return false; &#125; if (val &gt; 100) &#123; return false; &#125; return true;&#125; Wrong: 1234567891011function isPercentage(val) &#123; if (val &gt;= 0) &#123; if (val &lt; 100) &#123; return true; &#125; else &#123; return false; &#125; &#125; else &#123; return false; &#125;&#125; 或者针对这个例子我们可以更简短的解决它（逻辑优化）。 1234function isPercentage(val) &#123; var isInRange = (val &gt;= 0 &amp;&amp; val &lt;= 100); return isInRange;&#125; 给闭包命名请给闭包一个名称，表明你关心他们。这将会生成更好的堆栈跟踪、堆和CPU配置文件。 Right: 123req.on('end', function onEnd() &#123; console.log('winning');&#125;); Wrong: 123req.on('end', function() &#123; console.log('losing');&#125;); 禁止闭包嵌套使用闭包，但不要嵌套，不然会让你的代码变的一团糟。 Right: 1234567setTimeout(function() &#123; client.connect(afterConnect);&#125;, 1000);function afterConnect() &#123; console.log('winning');&#125; Wrong: 12345setTimeout(function() &#123; client.connect(function() &#123; console.log('losing'); &#125;);&#125;, 1000); 注释使用 /** ... */ 来进行多行注释，包括描述、指定所有参数、返回值的类型和值等相关信息。 123456789101112131415161718192021222324252627// bad// make() returns a new element// based on the passed in tag name//// @param &#123;String&#125; tag// @return &#123;Element&#125; elementfunction make(tag) &#123; // ...stuff... return element;&#125;// good/** * make() returns a new element * based on the passed in tag name * * @param &#123;String&#125; tag * @return &#123;Element&#125; element */function make(tag) &#123; // ...stuff... return element;&#125; 使用// 来进行单行注释. 使用单行注释时请独立起一行，并且在注释之前再空一行。 12345678910111213141516171819202122232425// badvar active = true; // is current tab// good// is current tabvar active = true;// badfunction getType() &#123; console.log('fetching type...'); // set the default type to 'no type' var type = this._type || 'no type'; return type;&#125;// goodfunction getType() &#123; console.log('fetching type...'); // set the default type to 'no type' var type = this._type || 'no type'; return type;&#125; 使用 FIXME or TODO作为前缀来帮助注释相关区域。帮助开发人员迅速定位和理解代码。例如FIXME -- need to figure this out or TODO -- need to implement. 使用// FIXME: 来指出问题。 1234567function Calculator() &#123; // FIXME: shouldn't use a global here total = 0; return this;&#125; 使用// TODO: 来说明如何解决。 1234567function Calculator() &#123; // TODO: total should be configurable by an options param this.total = 0; return this;&#125; 用注释或代码片段去解释难点，而不是过分使用来说琐碎的事情。 Right: 1234567891011121314// 'ID_SOMETHING=VALUE' -&gt; ['ID_SOMETHING=VALUE', 'SOMETHING', 'VALUE']var matches = item.match(/ID_([^
]+)=([^
]+)/));// This function has a nasty side effect where a failure to increment a// redis counter used for statistics will cause an exception. This needs// to be fixed in a later iteration.function loadUser(id, cb) &#123; // ...&#125;var isSessionValid = (session.expires &lt; Date.now());if (isSessionValid) &#123; // ...&#125; Wrong: 1234567891011121314// Execute a regexvar matches = item.match(/ID_([^
]+)=([^
]+)/);// Usage: loadUser(5, function() &#123; ... &#125;)function loadUser(id, cb) &#123; // ...&#125;// Check if the session is validvar isSessionValid = (session.expires &lt; Date.now());// If the session is validif (isSessionValid) &#123; // ...&#125; 强制类型转换在声明开始时就执行类型的强制转换Strings: 12345678910111213// =&gt; this.reviewScore = 9;// badvar totalScore = this.reviewScore + '';// goodvar totalScore = '' + this.reviewScore;// badvar totalScore = '' + this.reviewScore + ' total score';// goodvar totalScore = this.reviewScore + ' total score'; 使用 parseInt来转换Numbers的类型。 12345678910111213141516171819var inputValue = '4';// badvar val = new Number(inputValue);// badvar val = +inputValue;// badvar val = inputValue &gt;&gt; 0;// badvar val = parseInt(inputValue);// goodvar val = Number(inputValue);// goodvar val = parseInt(inputValue, 10); 如果在其他情况下需要使用位移等其他特性来转换，请留言解释为什么和你在做什么。 1234567// good/** * parseInt was the reason my code was slow. * Bitshifting the String to coerce it to a * Number made it a lot faster. */var val = inputValue &gt;&gt; 0; 注: 小心使用位移操作。数字代表64位的值，但位移操作总是返回一个32位的整数。位移大于32位会发生意外。最大32位是2147483647。 1232147483647 &gt;&gt; 0 //=&gt; 21474836472147483648 &gt;&gt; 0 //=&gt; -21474836482147483649 &gt;&gt; 0 //=&gt; -2147483647 Booleans: 12345678910var age = 0;// badvar hasAge = new Boolean(age);// goodvar hasAge = Boolean(age);// goodvar hasAge = !!age; 构造器分配方法给原型对象，来代替重写对象的原型方法。不然你可能会覆盖底层原有的原型！ 1234567891011121314151617181920212223function Jedi() &#123; console.log('new jedi');&#125;// badJedi.prototype = &#123; fight: function fight() &#123; console.log('fighting'); &#125;, block: function block() &#123; console.log('blocking'); &#125;&#125;;// goodJedi.prototype.fight = function fight() &#123; console.log('fighting');&#125;;Jedi.prototype.block = function block() &#123; console.log('blocking');&#125;; 原型的方法能够返回this 来帮助你的方法链。 1234567891011121314151617181920212223242526272829// badJedi.prototype.jump = function() &#123; this.jumping = true; return true;&#125;;Jedi.prototype.setHeight = function(height) &#123; this.height = height;&#125;;var luke = new Jedi();luke.jump(); // =&gt; trueluke.setHeight(20); // =&gt; undefined// goodJedi.prototype.jump = function() &#123; this.jumping = true; return this;&#125;;Jedi.prototype.setHeight = function(height) &#123; this.height = height; return this;&#125;;var luke = new Jedi();luke.jump() .setHeight(20); 写一个本地的toString()方法是可以的，只要你能确保它能有效作用。 123456789101112function Jedi(options) &#123; options || (options = &#123;&#125;); this.name = options.name || 'no name';&#125;Jedi.prototype.getName = function getName() &#123; return this.name;&#125;;Jedi.prototype.toString = function toString() &#123; return 'Jedi - ' + this.getName();&#125;; 事件当一个附加的数据负载到事件上（无论是DOM事件或其他私有事件例），传一个哈希来替代原始值，这样允许在之后使用的地方拓展参数并且不用找到每个使用的地方去改动它。 12345678// bad$(this).trigger('listingUpdated', listing.id);...$(this).on('listingUpdated', function(e, listingId) &#123; // do something with listingId&#125;); prefer: 12345678// good$(this).trigger('listingUpdated', &#123; listingId : listing.id &#125;);...$(this).on('listingUpdated', function(e, data) &#123; // do something with data.listingId&#125;); 模块 模块开发时要用!作为开头。 这样可以确保如果一个错误的模块忘记包含最后的分号，那么脚本连接时生产中就不会出现错误。 文件应该用驼峰命名，文件夹也应该使用相同的命名，同时输出的出口也用这个名字。 增加一个叫 noConflict() 的方法，来设置出口方法保证该方法的新版本能够去替换旧的版本，保证不产生方法冲突。 在模块头部声明 &#39;use strict&#39;; 。 123456789101112131415161718// fancyInput/fancyInput.js!function(global) &#123; 'use strict'; var previousFancyInput = global.FancyInput; function FancyInput(options) &#123; this.options = options || &#123;&#125;; &#125; FancyInput.noConflict = function noConflict() &#123; global.FancyInput = previousFancyInput; return FancyInput; &#125;; global.FancyInput = FancyInput;&#125;(this); jQuery定义jQ对象时请使用前缀$. 12345// badvar sidebar = $('.sidebar');// goodvar $sidebar = $('.sidebar'); 缓存 jQuery 查找出来的对象. 12345678910111213141516171819202122// badfunction setSidebar() &#123; $('.sidebar').hide(); // ...stuff... $('.sidebar').css(&#123; 'background-color': 'pink' &#125;);&#125;// goodfunction setSidebar() &#123; var $sidebar = $('.sidebar'); $sidebar.hide(); // ...stuff... $sidebar.css(&#123; 'background-color': 'pink' &#125;);&#125; 在层叠查询DOM结构时，使用$(&#39;.sidebar ul&#39;) 或者 parent &gt; child $(&#39;.sidebar &gt; ul&#39;)。 1234567891011121314// bad$('ul', '.sidebar').hide();// bad$('.sidebar').find('ul').hide();// good$('.sidebar ul').hide();// good$('.sidebar &gt; ul').hide();// good$sidebar.find('ul').hide(); Object.freeze, Object.preventExtensions, Object.seal, with, eval上面提到的东西，通通不要使用。 该文档是朋友所写，感觉不错，在此记录下，希望能被更多人看到。
